var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"꼴사납게 덜렁거리던 목이 드디어 떨어졌구나.","JPN":"無様に揺れていた首がようやく地に落ちたな。","ENG":"So that ugly, dangling head finally came off.","TWN":"那狼狽地搖晃著的頭，終於掉下來了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"바닥을 나뒹구는 기분은 어떠냐?","JPN":"地面を転がる気分はどうだ？","ENG":"How does it feel, rolling across the dirt like that?","TWN":"在地上滾動的感覺如何？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"…성급히 으스댈 것 없다.","JPN":"……調子に乗るでない。","ENG":"…Don't be so quick to gloat.","TWN":"…別急著炫耀。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"옛적에 갇혀 있던 때와 달리- 지금 본좌에겐 존자로 군림할 힘이 충만함이라.","JPN":"過去に閉じ込められていたかつてと違い、今の吾輩は天に君臨する力がみなぎっている。","ENG":"No longer bound as I once was, I now possess power overflowing, enough to rule as a revered sovereign!","TWN":"與從前被囚禁時不同—現在本座充滿了君臨萬物的力量。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"현세의 인간들이 흘린 피와 한이 제물 되어 이 몸은 몇 번이고 고쳐 일어설 것이다.","JPN":"現世の人間が流した血と怨念が生贄となり、吾輩は何度でも立ち上がるだろう。","ENG":"The blood and resentment of mankind in this age have become my offering. With it, I will rise again and again.","TWN":"現世的人類流下的鮮血和怨恨將成為祭品，我的身體會一次又一次地重新站起來。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범의 목에서… 머리가 다시 자라고 있어요.","JPN":"虎の首から……頭が生えてきます。","ENG":"The Tiger's head… it's growing back from the neck.","TWN":"老虎的脖子…頭又長出來了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"참으로 흉물이군. 떨어진 머리는 붙일 필요도 없다는 건가.","JPN":"実に禍々しい光景だな。落とされた頭をつける必要もないということか。","ENG":"What a monstrosity. So it doesn't even need the severed one reattached.","TWN":"真是個不祥的東西。掉了的頭也不需要再接上嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나, 한 번 죽은 녀석을 되살아나게 둘 생각은 없다.","JPN":"だが、一度死んだやつを蘇らせるつもりはない。","ENG":"Still, I won't let that thing rise again.","TWN":"但是，我可不打算讓已經死過一次的傢伙復活。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"소용없는 짓이다.","JPN":"無駄だ。","ENG":"A wasted effort.","TWN":"這是徒勞的。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"이 몸에 깃든 힘은 그 어느 때보다 넘치고 있으니…","JPN":"この体に宿る力はいつになく溢れて……","ENG":"I hold more power than ever…","TWN":"這具身體裡蘊含的力量，比任何時候都要充沛…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"…무어냐?","JPN":"……何だ？","ENG":"…What is this?","TWN":"…什麼？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"어찌하여 이 몸의 수복이 이토록 더딘 것이지?","JPN":"なぜ体の修復が遅れている？","ENG":"Why is my recovery slowing?","TWN":"為什麼這具身體的修復如此緩慢？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네놈이 둑에 물을 채웠다고 해서 그 물의 영원한 주인이란 뜻은 아니지.","JPN":"貴様が堤に水を満たしたからといって、いつまでもその水の主になるわけではないからだ。","ENG":"Just because you filled a dam with water doesn't mean you're its eternal master.","TWN":"你以為只要築起了水壩，那水就永遠屬於你嗎？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"둑이 무너지면, 고여있던 물은 그저 섭리를 따라 아래로 흘러갈 뿐.","JPN":"堤が崩れれば、溜まっていた水は下へと流れるのが世の摂理。","ENG":"When a dam breaks, the stagnant water simply follows its nature and flows downward.","TWN":"水壩一旦崩塌，積聚的水只會順著道理流向下方。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"네놈… 무슨 뜻 모를 허언을 지껄이는 것이냐?","JPN":"貴様……何訳の分からんことをほざいている？","ENG":"You… speak nonsense. What are you babbling about?","TWN":"你這傢伙…在說什麼莫名其妙的廢話？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"간단한 얘기다.","JPN":"簡単な話だ。","ENG":"It's simple.","TWN":"很簡單。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"목이 잘린 네 놈에겐 그 많은 힘을 붙잡아둘 여력이 없으니, 쏟아진 힘이 그 아래의 마땅한 주인을 찾아갔다는 뜻이다.","JPN":"首が斬られたお前には、莫大な力を抑え込めるだけの余力がない。そうやって溢れ出た力が、その下の然るべき主へと行き着いたというわけだ。","ENG":"With your neck severed, you had no strength left to contain all that power. That is why the spilled power simply went to find its rightful owner below.","TWN":"頭被砍下的你，沒有能力抓住那麼龐大的力量，所以湧出的力量，找到了下一個應有的主人。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"마땅한 주인이라?","JPN":"然るべき主？","ENG":"Rightful owner?","TWN":"應有的主人？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"본좌와 같은 힘을 쓰는 존재가 달리 있을 리…","JPN":"吾輩と同類の力を振るう存在など、他にいるはずが……","ENG":"There can be no other being with this power but m–","TWN":"除了本座之外，還有誰能使用同樣的力量…"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"…설마?","JPN":"……まさか？","ENG":"…It can't be!","TWN":"…難道是？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"……","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_111"},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생…!","JPN":"ショウ……！","ENG":"Seosaeng…!","TWN":"書生…！"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"네놈이… 어떻게 아직도…?","JPN":"貴様……なぜまだ……？","ENG":"How… are you still alive…?","TWN":"你這傢伙…怎麼還…？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건… 환 같은 건가?","JPN":"これは……丸薬か？","ENG":"Is this… some kind of pill?","TWN":"這是… 幻覺藥嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일회용 각성제라고 생각하게나.","JPN":"使い捨ての覚醒剤だと思ってくれ。","ENG":"It is called Deathward. Think of it as a one-time-use stimulant.","TWN":"這是名為續命術的藥。把它當成一次性的覺醒劑吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"먹는다고 괴력이 생기는 건 아니지만, 죽을 것 같은 상황에 처하면 목숨을 연명하는 데 도움이 될 걸세.","JPN":"飲んだからといって怪力になるわけではないが、瀕死の状況で延命するぐらいなら役に立つだろう。","ENG":"If you ever find yourself facing inevitable death… this might help you stay alive.","TWN":"如果你面臨無法避免的死亡，這將有助於你延續生命。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"은인이 준 약을 좀 먹어뒀소.","JPN":"恩人にもらった薬があったので、飲んでおいた。","ENG":"I took the medicine my savior gave me.","TWN":"我吃了恩人給的藥。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"재료는 모르겠으나, 사무치는 쓴맛에 정신이 번쩍 들더구려.","JPN":"何で出来ているかはしらんが、しびれるような苦味に気が引き締まってな。","ENG":"Not sure what it's made of, but the bitterness alone shocked me awake.","TWN":"不知道是什麼材料，但那股刺骨的苦味讓我清醒了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"정말로… 괜찮은 거야?","JPN":"本当に……大丈夫なの？","ENG":"Is he… really okay?","TWN":"你真的…沒事嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"괜찮지 않을 게다.","JPN":"大丈夫ではないだろう。","ENG":"He's not.","TWN":"不會沒事。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>정신살이</color>는 죽어야 할 자를 강제로 연명시키는 극약처방이니까.","JPN":"<color=#ffd34c>精神丸</color>は死を目前にした者を強制的に延命させる劇薬だ。","ENG":"The <color=#ffd34c>Deathward</color> pill is an extreme measure that forces someone on the verge of death to keep living.","TWN":"<color=#ffd34c>續命術</color>是讓本該死去的人強行續命的緊急療法。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"기껏해야 한 식경이 한계겠지.","JPN":"せいぜい一飯の時間が限界だろう。","ENG":"At most, he has half an hour.","TWN":"最多也只能維持半天。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나, 역할을 다 하기에 부족함은 없을 거요.","JPN":"しかし、役目を果たすには十分なはずだ。","ENG":"That's more than enough to do my part.","TWN":"然而，這段時間足以完成我的任務。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"역할이라니…","JPN":"役目って……","ENG":"Your part…?","TWN":"任務…？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 이미 할 만큼 했잖아. 뭘 더 하겠다는 거야?","JPN":"あなたはもう十分自分を犠牲にしたじゃない。これ以上何をするというの？","ENG":"Haven't you done more than enough already? What else are you planning?","TWN":"你已經犧牲夠多了。還要再做什麼？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"범은 수없이 많은 인명을 희생시켜 막대한 힘을 모았지.","JPN":"虎は数多の人命を犠牲にして莫大な力を手に入れた。","ENG":"The Tiger gathered tremendous power by sacrificing countless lives.","TWN":"老虎犧牲了無數生命，積累了龐大的力量。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 이 힘을 모두 써서, 모든 것을 원점으로 되돌려 놓겠소.","JPN":"某がこの力を存分に使い切り、すべてを原点に戻そう。","ENG":"I'll use all the power I have to return everything to its origin.","TWN":"我將用盡這股力量，讓一切回到原點。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"범이 현세에 당도하기 이전의 시간으로.","JPN":"虎が現世に辿り着く前の時間へ。","ENG":"To the moment before the Tiger crossed into this world.","TWN":"回到老虎來到現世之前的時間。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"시간을… 되돌린다고?","JPN":"時を……巻き戻すつもりなの？","ENG":"You're going to… turn back time?","TWN":"讓時間…倒流？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"개미 한 마리가 둑을 풀겠다는 꼴이로다.","JPN":"アリ1匹に堤が崩せるものか。","ENG":"Like an ant trying to move a mountain.","TWN":"就像一隻螞蟻想拆掉水壩一樣。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"본좌의 작은 조각일 뿐인 네놈이 그런 큰 힘을 다루었다간, 죽음으로 끝나지 않는다.","JPN":"吾輩の小さな欠片にすぎぬ貴様が、そのような莫大な力を扱えば、死ぬだけでは済まない。","ENG":"You're but a fragment of me. If you try to wield such power, it will bring an end far worse than death.","TWN":"你只是本座的一小片碎片，如果操縱如此龐大力量，不僅僅是死亡。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"육신뿐 아니라 그 혼백도 갈가리 찢겨 나가, 윤회에조차 이르지 못하리라.","JPN":"その血肉のみならず魂魄まで引き裂かれ、輪廻にも辿り着けないだろう。","ENG":"Not only your body but also your soul will be torn apart and scattered beyond even reincarnation.","TWN":"你的肉身，連同魂魄都會被撕裂，甚至無法輪迴。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"듣던 중 반가운 말이로군.","JPN":"それは良いことを聞いた。","ENG":"I've been waiting to hear that.","TWN":"這話聽起來真令人高興。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_101"},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"누구도 원치 않던 이 비극의 순환을 끊어낼 방법을 드디어 찾지 않았나.","JPN":"誰も望まぬこの悲劇の循環を断ち切る方法がやっと見つかったのだからな。","ENG":"I've finally found a way to end this tragic cycle that no one ever wanted.","TWN":"我終於找到了方法，可以切斷這場無人期盼的悲劇輪迴。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_102"},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"싫어. 왜 그런 말을 하는 거야?","JPN":"いやよ。どうしてそんなことを言うの？","ENG":"No. Why would you say something like that?","TWN":"不要。為什麼要說這種話？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_121"},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"되풀이되는 비극은 싫지만… 당신을 만날 수 없는 것도 싫어.","JPN":"悲劇が繰り返されるのはいやだけど……あなたに会えなくなるのもいや。","ENG":"I hate this repeating tragedy, but… I hate not being able to see you even more.","TWN":"雖然我不喜歡反覆的悲劇…但也不想無法再見到你。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_122"},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…연화.","JPN":"……レンカ。","ENG":"…Yeonhwa.","TWN":"…蓮華。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_103"},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"난 그대가 내게 살아갈 기회를 준 지난 수년 간, 아주 소중한 인연들을 만났소.","JPN":"そなたのおかげで生きる機会をもらったこの数年間、某にはかけがえのない因縁ができた。","ENG":"In the past few years, since you gave me a reason to live, I met the most precious people.","TWN":"在過去的幾年裡，你給了我活下去的機會，我遇到了許多珍貴的人。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_104"},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"마음을 헤아려주는 멋진 동료를 만나고…","JPN":"心を察してくれる素敵な仲間に出会い……","ENG":"A friend who understood my heart…","TWN":"我遇到了能體諒我的好夥伴…"},"stage":{"bg":"CHAMBER","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_105"},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내가 얼마나 소중한 사람이 될 수 있는지 귀여운 제자가 알려주었으며…","JPN":"可愛い弟子が、自分がいかに大事な人になれるか教えてくれ……","ENG":"A bright-eyed apprentice who showed me I could mean something to others…","TWN":"可愛的弟子告訴了我，我能成為多麼珍貴的人…"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_106"},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나를 닮아 아픔을 나눌 수 있는 친구도 사귀었지.","JPN":"某に似た、痛みを分かち合える友にも出会えた。","ENG":"Even made a friend who shared my pain.","TWN":"我還交了一個和我一樣，可以分享痛苦的朋友。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_107"},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"비록 그 인연의 마지막이 아름다운 작별은 아니었을지 언정…","JPN":"最後、美しい別れ方はできなかったが……","ENG":"Even if those bonds didn't end with a perfect farewell…","TWN":"儘管這段緣分的最後，不是美好的告別…"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_108"},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그들과 함께 해온 짧은 시간이 헛되다 생각한 적은 단 한 번도 없었네.","JPN":"一瞬たりとも、彼らと共に過ごした短い時間が無駄なものだったと思ったことはない。","ENG":"Not once did I regret the time I had with them.","TWN":"但我從未覺得，與他們共度的短暫時光是徒勞的。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_109"},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러니 이젠, 내가 받은 은혜를 제자리에 돌려놓을 차례인 거요.","JPN":"だから今度は、某がその恩を返す番だ。","ENG":"So now, it's my turn to return the favor.","TWN":"所以現在，輪到我把得到的恩惠，歸還給應有的位置。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_110"},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가…","JPN":"私……","ENG":"Will I be able to…","TWN":"我…"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_123"},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신을 기억할 수 있을까?","JPN":"あなたを、思い出せるかしら。","ENG":"Still remember you?","TWN":"還能記得你嗎？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_124"},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"세상 만사는 돌고 도는 수레바퀴와 같으니, 옛 이야기에 묶여 살아가는 우리네 삶도 마찬가지일 것이요.","JPN":"巡り巡る歯車のようなもの、それが世の理。昔話に囚われて生きる我らの人生も同じだろう。","ENG":"All things turn like a wheel. Just like we live tethered to stories of the past.","TWN":"世間萬物就像不斷轉動的車輪，我們被舊故事束縛的人生也是如此。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_112"},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"수천만 백 번 되풀이된들 달라지는 것 없는 악바리와 화류춘몽의 한탄가처럼… 한 많고 수많은 생애를 보냈지.","JPN":"数千万回を繰り返しても変わらぬ、一場の春夢のごとく……無念と悔恨に満ちた人生を幾度も送った。","ENG":"In countless lives, through countless cycles, I've sung the same mournful song of stubborn defiance and fleeting spring dreams.","TWN":"像那數千數萬次重複，卻從未改變的頑固和黃粱一夢的嘆息一樣…我度過了充滿遺憾的無數人生。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_113"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"생애마다 불리는 이름은 달랐으나, 생애마다 사랑하는 여인을 만났고.","JPN":"その生ごとに呼ばれる名は違えど、毎回愛する女性に出会い……","ENG":"Though I went by different names in each life, I always met the same woman I loved.","TWN":"每個人生，我的名字都不同，但每個生命，我都會遇到心愛的女人。"},"stage":{"bg":"HANOK","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_114"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 생애를 넘어 그녀에게 언제나 하나의 별명으로 불리었네.","JPN":"生を超越して彼女から常に一つの別名で呼ばれた。","ENG":"And across every life, she always called me by the same name.","TWN":"我跨越了生命，她總是給我一個獨特的暱稱。"},"stage":{"bg":"HANOK","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_115"},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"생애의 시작은 언제나 다른 이름 석 자였으나, 내 운명의 꽃은 언제나 한 여인이 그 이름을 불러주었을 때 싹을 틔웠소.","JPN":"生の始まりに与えられた名前が何であれ、某の運命の花は常に、一人の女性からその名を呼ばれた時に芽吹いた。","ENG":"My name may have changed in each life, but moment the flower of my fate bloomed was always when that one woman called me by my true name.","TWN":"人生的開始總是有不同的名字，但我的命運之花，總是在一個女人呼喚我名字時發芽。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_116"},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러니…","JPN":"だから……","ENG":"So…","TWN":"所以…"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_117"},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"당장 지는 꽃에 너무 서글퍼 말게.","JPN":"今花が散ることを悲しまないでくれ。","ENG":"Don't be too sad if this flower withers now.","TWN":"別為眼前凋謝的花朵感到悲傷。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_118"},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"영겁이 지난다 해도, 그대가 내 이름을 부르는 날…","JPN":"永劫の時が過ぎても、そなたが某の名を呼んでくれれば……","ENG":"Even if it takes an eternity, when the day comes that you call my name again…","TWN":"就算過了永劫，只要你呼喚我的名字…"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_119"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"나는 어디서나 피어날 꽃일 테니.","JPN":"某はどこにいても、花を咲かせるであろうから。","ENG":"I'll bloom once more, wherever I may be.","TWN":"我就會是隨處綻放的花朵。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_120"},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 대책이 성공리에 마무리된다면, 대규모 현실 개변이 많은 것들을 바꾸겠지.","JPN":"この対策が成功裏に進めば、それに伴い大規模現実改変が多くのものを変えてしまうだろう。","ENG":"If this plan succeeds, a large-scale change in reality will happen.","TWN":"如果這個計畫成功，大規模的現實改變會改變很多事情。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지난 수년 간 만들어진 역사와 물건들이 송두리째 없던 것이 될 걸세.","JPN":"過去数年間築き上げられた歴史や発明品が、まったく存在しなかったことになる。","ENG":"Years of history and everything built during that time will simply vanish.","TWN":"過去幾年創造的歷史和物品，將會徹底消失。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"특별히 남기고 싶은 것이 있나?","JPN":"特別に、残したいものはないか？","ENG":"Is there anything you'd like to leave behind?","TWN":"有什麼特別想留下來的嗎？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…기상조절장치.","JPN":"……気象調節装置。","ENG":"…The Weather Control System.","TWN":"…氣象調節裝置。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"후에 관리국에서 그것을 만들어 베풀어주시오.","JPN":"後日管理局でそれを作り、供給してくれ。","ENG":"Please have the Administration recreate and distribute it.","TWN":"日後請管理局製造並運用吧。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"도시의 아이들이 꽃놀이를 즐길 수 있도록.","JPN":"都市の子どもたちが、花見を楽しめるように。","ENG":"So the children in the city can enjoy the flowers too.","TWN":"好讓城市的孩童們能夠享受賞花之樂。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};